import{_ as t,o as a,c as i,ae as n}from"./chunks/framework.D8e0q88G.js";const p=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"SprintLab","text":"Sprint Kinematic Analysis from Video","tagline":"Research-level biomechanics. No lab required. Free and open-source.","actions":[{"theme":"brand","text":"Get Started","link":"/architecture"},{"theme":"alt","text":"Math Reference","link":"/math"},{"theme":"alt","text":"GitHub","link":"https://github.com/mvch1ne/zero"}]},"features":[{"title":"133-Keypoint Pose Estimation","details":"Powered by RTMLib's Wholebody3d model (MMPose). Tracks the full body — joints, feet, hands, face — at research-grade accuracy via ONNX Runtime."},{"title":"Complete Biomechanics Metrics","details":"Ground contact times, flight times, step length, step frequency, joint angles, angular velocities, angular accelerations, and center-of-mass trajectory — all in real units."},{"title":"Calibration-Based Scaling","details":"Draw a reference line over any known distance in the frame. Every pixel measurement is converted to metres automatically."},{"title":"Pure Math Layer","details":"All biomechanics computation lives in framework-free TypeScript functions. Aspect-ratio corrected, physically meaningful, and fully unit-tested."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}`),r={name:"index.md"};function o(s,e,l,c,h,d){return a(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="what-is-sprintlab" tabindex="-1">What is SprintLab? <a class="header-anchor" href="#what-is-sprintlab" aria-label="Permalink to &quot;What is SprintLab?&quot;">​</a></h2><p>SprintLab is a web application for kinematic analysis of sprint videos. Upload a video, run pose estimation, calibrate a reference distance, and get a full breakdown of your sprint mechanics — joint angles, contact times, center-of-mass speed, and more.</p><p>It was built by an athlete and engineer from Ghana, West Africa, where biomechanics labs and sports science infrastructure are essentially nonexistent. The goal is to give any athlete, anywhere, access to the kind of analysis that was previously only available in well-funded research settings.</p><h2 id="how-to-read-these-docs" tabindex="-1">How to read these docs <a class="header-anchor" href="#how-to-read-these-docs" aria-label="Permalink to &quot;How to read these docs&quot;">​</a></h2><ul><li><strong><a href="/zero/architecture.html">Architecture</a></strong> — start here for the big picture: how the frontend, backend, and data pipeline fit together.</li><li><strong><a href="/zero/math.html">Math Reference</a></strong> — all the equations that power the metrics engine, written out fully with derivations and design rationale.</li><li><strong>Frontend</strong> — deep dives into each major component: Viewport, Pose Engine, Calibration, Metrics Engine, and Telemetry.</li><li><strong>Backend</strong> — the FastAPI server, the SSE streaming protocol, and the keypoint wire format.</li><li><strong><a href="/zero/testing.html">Testing</a></strong> — test strategy, what is covered, and how to run the suites.</li></ul>',5)])])}const u=t(r,[["render",o]]);export{p as __pageData,u as default};
